import{_ as t,a,b as o,c as i,d as r}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as n,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const j=JSON.parse('{"title":"Dodawanie kanału OneDrive","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/onedrive.md","filePath":"pl-PL/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"pl-PL/upload/onedrive.md"};function p(k,e,h,u,z,b){return d(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="dodawanie-kanału-onedrive" tabindex="-1">Dodawanie kanału OneDrive <a class="header-anchor" href="#dodawanie-kanału-onedrive" aria-label="Permalink to &quot;Dodawanie kanału OneDrive&quot;">​</a></h1><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Wymaganie</th><th>Dlaczego jest potrzebne</th></tr></thead><tbody><tr><td>Konto Microsoft</td><td>Do stron administracyjnych Microsoft i autoryzacji OneDrive</td></tr><tr><td>Domena ImgBed</td><td>Do URL-a callback OAuth</td></tr><tr><td>Rejestracja aplikacji</td><td>Do utworzenia <code>Client ID</code> i <code>Client Secret</code></td></tr><tr><td>Konto OneDrive</td><td>Jako właściwe miejsce przechowywania plików</td></tr></tbody></table><h2 id="konfiguracja" tabindex="-1">Konfiguracja <a class="header-anchor" href="#konfiguracja" aria-label="Permalink to &quot;Konfiguracja&quot;">​</a></h2><h3 id="krok-1-otworz-microsoft-entra-id" tabindex="-1">Krok 1: Otwórz Microsoft Entra ID <a class="header-anchor" href="#krok-1-otworz-microsoft-entra-id" aria-label="Permalink to &quot;Krok 1: Otwórz Microsoft Entra ID&quot;">​</a></h3><ol><li>Otwórz <code>portal.azure.com</code>.</li><li>Wyszukaj u góry <code>Microsoft Entra ID</code>.</li><li>Jeśli strona nie pojawia się w menu, wybierz:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Otwórz <code>Microsoft Entra ID</code>.</li><li>Otwórz <code>App registrations</code>.</li><li>Kliknij <code>New registration</code>.</li></ol><h3 id="krok-2-zarejestruj-aplikacje" tabindex="-1">Krok 2: Zarejestruj aplikację <a class="header-anchor" href="#krok-2-zarejestruj-aplikacje" aria-label="Permalink to &quot;Krok 2: Zarejestruj aplikację&quot;">​</a></h3><p>Na stronie <code>New registration</code> wypełnij:</p><table tabindex="0"><thead><tr><th>Pole</th><th>Co wpisać</th></tr></thead><tbody><tr><td>Name</td><td>Czytelna nazwa, np. <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Wybierz według tabeli poniżej</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Wskazówki dotyczące typu konta:</p><table tabindex="0"><thead><tr><th>Scenariusz</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Tylko osobisty OneDrive</td><td>Wybierz opcję dla osobistych kont Microsoft.</td></tr><tr><td>Konta osobiste i firmowe/szkolne</td><td>Wybierz opcję obsługującą konta osobiste i organizacyjne.</td></tr><tr><td>Tylko firmowy lub szkolny OneDrive</td><td>Wybierz opcję dla kont organizacyjnych.</td></tr></tbody></table><p>Po wypełnieniu formularza kliknij rejestrację.</p><p><img src="'+t+'" alt="Utwórz aplikację OneDrive" loading="lazy"></p><h3 id="krok-3-skopiuj-informacje-aplikacji" tabindex="-1">Krok 3: Skopiuj informacje aplikacji <a class="header-anchor" href="#krok-3-skopiuj-informacje-aplikacji" aria-label="Permalink to &quot;Krok 3: Skopiuj informacje aplikacji&quot;">​</a></h3><p>Po utworzeniu aplikacji skopiuj z widoku przeglądu:</p><table tabindex="0"><thead><tr><th>Pole Microsoft</th><th>Pole ImgBed</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> dla kont organizacyjnych</td></tr></tbody></table><p><img src="'+a+'" alt="Application ID i Tenant ID" loading="lazy"></p><h3 id="krok-4-utworz-client-secret" tabindex="-1">Krok 4: Utwórz Client Secret <a class="header-anchor" href="#krok-4-utworz-client-secret" aria-label="Permalink to &quot;Krok 4: Utwórz Client Secret&quot;">​</a></h3><ol><li>Otwórz <code>Certificates &amp; secrets</code>.</li><li>Kliknij <code>New client secret</code>.</li><li>Wpisz dowolny, rozpoznawalny opis.</li><li>Wybierz okres ważności.</li><li>Od razu po utworzeniu skopiuj <code>Value</code>.</li></ol><p><img src="'+o+'" alt="Zapisz wartość Client Secret" loading="lazy"></p><h3 id="krok-5-dodaj-uprawnienia-api" tabindex="-1">Krok 5: Dodaj uprawnienia API <a class="header-anchor" href="#krok-5-dodaj-uprawnienia-api" aria-label="Permalink to &quot;Krok 5: Dodaj uprawnienia API&quot;">​</a></h3><ol><li>Otwórz <code>API permissions</code>.</li><li>Kliknij <code>Add a permission</code>.</li><li>Wybierz <code>Microsoft Graph</code>.</li><li>Wybierz <code>Delegated permissions</code>.</li><li>Dodaj te uprawnienia:</li></ol><table tabindex="0"><thead><tr><th>Uprawnienie</th><th>Cel</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Przesyłanie plików, tworzenie katalogów i usuwanie plików</td></tr><tr><td><code>offline_access</code></td><td>Pozwala ImgBed uzyskać <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>Czyta informacje o koncie i limicie</td></tr></tbody></table><h3 id="krok-6-wypełnij-kanał-onedrive" tabindex="-1">Krok 6: Wypełnij kanał OneDrive <a class="header-anchor" href="#krok-6-wypełnij-kanał-onedrive" aria-label="Permalink to &quot;Krok 6: Wypełnij kanał OneDrive&quot;">​</a></h3><p>W Ustawieniach przesyłania wybierz <code>OneDrive</code> i wypełnij:</p><table tabindex="0"><thead><tr><th>Pole ImgBed</th><th>Co wpisać</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Czytelna nazwa, np. <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>Skopiowana wartość <code>Client Secret Value</code></td></tr><tr><td>Tenant ID</td><td>Według tabeli poniżej</td></tr><tr><td>Refresh Token</td><td>Na razie zostaw puste</td></tr><tr><td>Katalog główny</td><td>Opcjonalnie. Domyślnie <code>imgbed</code>.</td></tr><tr><td>Notatka</td><td>Opcjonalnie</td></tr></tbody></table><p><img src="'+i+'" alt="Konfiguracja kanału OneDrive" loading="lazy"></p><p>Jak wypełnić <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Wybrany typ konta</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Konta osobiste</td><td><code>consumers</code></td></tr><tr><td>Konta osobiste i organizacyjne</td><td><code>common</code></td></tr><tr><td>Tylko bieżąca organizacja</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="krok-7-pobierz-refresh-token" tabindex="-1">Krok 7: Pobierz Refresh Token <a class="header-anchor" href="#krok-7-pobierz-refresh-token" aria-label="Permalink to &quot;Krok 7: Pobierz Refresh Token&quot;">​</a></h3><ol><li>W ImgBed kliknij <code>Get Token</code>.</li><li>Zaloguj się na konto Microsoft, które chcesz podłączyć.</li><li>Zatwierdź autoryzację.</li><li>Strona callback pokaże <code>Refresh Token</code>.</li><li>Skopiuj go.</li><li>Wróć do ImgBed i wklej go w polu <code>Refresh Token</code>.</li></ol><p><img src="'+r+`" alt="Kopiowanie Refresh Token" loading="lazy"></p><h3 id="krok-8-zapisz-kanał" tabindex="-1">Krok 8: Zapisz kanał <a class="header-anchor" href="#krok-8-zapisz-kanał" aria-label="Permalink to &quot;Krok 8: Zapisz kanał&quot;">​</a></h3><p>Po wypełnieniu wszystkich pól zapisz kanał.</p><h2 id="szybki-przebieg" tabindex="-1">Szybki przebieg <a class="header-anchor" href="#szybki-przebieg" aria-label="Permalink to &quot;Szybki przebieg&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otwórz portal.azure.com</span></span>
<span class="line"><span>-&gt; Wyszukaj Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Otwórz App registrations</span></span>
<span class="line"><span>-&gt; Zarejestruj nową aplikację</span></span>
<span class="line"><span>-&gt; Wypełnij Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Zarejestruj</span></span>
<span class="line"><span>-&gt; Skopiuj Application (client) ID</span></span>
<span class="line"><span>-&gt; Sprawdź callback URL w Authentication</span></span>
<span class="line"><span>-&gt; Utwórz Client Secret w Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Dodaj uprawnienia w API permissions</span></span>
<span class="line"><span>-&gt; Wpisz Client ID / Client Secret / Tenant ID w ImgBed</span></span>
<span class="line"><span>-&gt; Kliknij Get Token</span></span>
<span class="line"><span>-&gt; Skopiuj Refresh Token ze strony callback</span></span>
<span class="line"><span>-&gt; Wklej go w ImgBed i zapisz</span></span></code></pre></div><h2 id="referencje" tabindex="-1">Referencje <a class="header-anchor" href="#referencje" aria-label="Permalink to &quot;Referencje&quot;">​</a></h2><ol><li>Rejestracja aplikacji Microsoft Entra: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const w=n(c,[["render",p]]);export{j as __pageData,w as default};
